import type { Locale } from "./i18n.js";

// Generated translation catalog for ko/ja/zh. Keyed on the canonical English
// source string (gettext-style); a missing entry falls back to English so the
// report stays coherent even when partly untranslated. English output is never
// routed through here (t() short-circuits on "en"), so it remains byte-identical.
export type LocaleStrings = Partial<Record<Exclude<Locale, "en">, string>>;

export interface MessagePattern {
  test: RegExp;
  fill: Partial<Record<Exclude<Locale, "en">, (match: RegExpMatchArray) => string>>;
}

