function fillTemplate(template: string, match: RegExpMatchArray): string {
  return template.replace(/\{(\d+)\}/g, (_, index: string) => match[Number(index)] ?? "");
}

export const MESSAGE_PATTERNS: MessagePattern[] = RAW_PATTERNS.map((pattern) => {
  const fill: MessagePattern["fill"] = {};
  if (pattern.ko !== undefined) fill.ko = (match) => fillTemplate(pattern.ko ?? "", match);
  if (pattern.ja !== undefined) fill.ja = (match) => fillTemplate(pattern.ja ?? "", match);
  if (pattern.zh !== undefined) fill.zh = (match) => fillTemplate(pattern.zh ?? "", match);
  return { test: new RegExp(pattern.source, pattern.flags), fill };
});
